ALL_EXAMPLES = PROMPT_EXAMPLES


def _main_prompt_example() -> dict[str, Any]:
    return PROMPT_EXAMPLES[0]


def _assert_annotation_ok(annotation: str) -> None:
    inner, _tells, meta, ok, end = root_splits(tx=annotation)
    assert ok and meta is not None and end == len(annotation)
    diag = format_diagnostics(output=annotation, document=inner)
    assert diag["ok"], diag


def _assert_examples_ok() -> None:
    for example in PROMPT_EXAMPLES:
        for key in ("human_annotated_document", "ai_annotated_document"):
            _assert_annotation_ok(annotation=example[key])


def style_example_for_label(target_label: str, style_example_index: int | None = None) -> str:
    if style_example_index is None:
        example = _main_prompt_example()
    else:
        example = PROMPT_EXAMPLES[style_example_index % len(PROMPT_EXAMPLES)]
    if target_label == "AI text":
        annotated = example["ai_annotated_document"]
        reasoning = example["how_i_annotated_ai"]
    elif target_label == "human text":
        annotated = example["human_annotated_document"]
        reasoning = example["how_i_annotated_human"]
    else:
        raise ValueError(f"unsupported target_label: {target_label}")
    escaped_human_document = escape_document_piece(example["human_document"])
    escaped_ai_document = escape_document_piece(example["ai_document"])
    return f"""Style example for {target_label}:
Human:
<<<
{escaped_human_document}
>>>

AI:
<<<
{escaped_ai_document}
>>>

Annotated {target_label}:
{annotated}

How I annotated the {target_label}:
{reasoning}"""
